patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineVectorOps.cpp b/llvm/lib/Transforms/InstCombine/InstCombineVectorOps.cpp
index 454fe5a91d37..b0910c37bcc3 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineVectorOps.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineVectorOps.cpp
@@ -2900,7 +2900,11 @@ Instruction *InstCombinerImpl::visitShuffleVectorInst(ShuffleVectorInst &SVI) {
   if (Instruction *I = foldIdentityPaddedShuffles(SVI))
     return I;

-  if (match(RHS, m_Constant())) {
+  // We can fold a shuffle of a select if the second shuffle operand is not
+  // "poison-producing". If it has concrete non-zero values, it may incorrectly
+  // replace a poison operand of the select.
+  if (isa<UndefValue>(RHS) || isa<PoisonValue>(RHS) ||
+      match(RHS, m_Zero())) {
     if (auto *SI = dyn_cast<SelectInst>(LHS)) {
       // We cannot do this fold for elementwise select since ShuffleVector is
       // not elementwise.

